  1→/**
  2→ * Limites par plan tarifaire pour la fonctionnalité LLM Source of Truth
  3→ * Ces limites déterminent ce que chaque type d'utilisateur peut créer/stocker
  4→ */
  5→
  6→import type { PlanLimits } from '@/types/llm-sources';
  7→
  8→export const LLM_SOURCE_PLAN_LIMITS: Record<'free' | 'pro' | 'agency', PlanLimits> = {
  9→  free: {
 10→    maxSources: 1,              // 1 seule source
 11→    maxServices: 5,              // 5 services max
 12→    maxUseCases: 3,              // 3 cas d'usage max
 13→    maxFaq: 10,                  // 10 FAQ max
 14→    maxReferencePages: 5,        // 5 pages de référence max
 15→    autoGeneration: false,       // Pas de génération automatique
 16→    customSlug: false,           // Slug auto-généré seulement
 17→    versionHistory: false,       // Pas d'historique des versions
 18→    apiAccess: false,            // Pas d'accès API
 19→  },
 20→  pro: {
 21→    maxSources: 3,               // 3 sources max
 22→    maxServices: 20,             // 20 services max
 23→    maxUseCases: 10,             // 10 cas d'usage max
 24→    maxFaq: 50,                  // 50 FAQ max
 25→    maxReferencePages: 20,       // 20 pages de référence max
 26→    autoGeneration: true,        // Génération automatique activée
 27→    customSlug: true,            // Slug personnalisé autorisé
 28→    versionHistory: true,        // Historique des versions activé
 29→    apiAccess: true,             // Accès API activé
 30→  },
 31→  agency: {
 32→    maxSources: 50,              // 50 sources max (multi-clients)
 33→    maxServices: -1,             // Illimité (-1)
 34→    maxUseCases: -1,             // Illimité
 35→    maxFaq: -1,                  // Illimité
 36→    maxReferencePages: -1,       // Illimité
 37→    autoGeneration: true,        // Génération automatique activée
 38→    customSlug: true,            // Slug personnalisé autorisé
 39→    versionHistory: true,        // Historique des versions activé
 40→    apiAccess: true,             // Accès API activé
 41→    whiteLabel: true,            // White-label activé
 42→    bulkExport: true,            // Export en masse activé
 43→  },
 44→};
 45→
 46→/**
 47→ * Obtenir les limites pour un plan donné
 48→ */
 49→export function getPlanLimits(planTier: string): PlanLimits {
 50→  const normalizedPlan = planTier.toLowerCase() as 'free' | 'pro' | 'agency';
 51→
 52→  if (!LLM_SOURCE_PLAN_LIMITS[normalizedPlan]) {
 53→    // Par défaut, retourner les limites du plan free
 54→    return LLM_SOURCE_PLAN_LIMITS.free;
 55→  }
 56→
 57→  return LLM_SOURCE_PLAN_LIMITS[normalizedPlan];
 58→}
 59→
 60→/**
 61→ * Vérifier si une limite est atteinte
 62→ * @param currentCount Nombre actuel d'éléments
 63→ * @param maxAllowed Maximum autorisé (-1 = illimité)
 64→ */
 65→export function isLimitReached(currentCount: number, maxAllowed: number): boolean {
 66→  // -1 signifie illimité
 67→  if (maxAllowed === -1) {
 68→    return false;
 69→  }
 70→
 71→  return currentCount >= maxAllowed;
 72→}
 73→
 74→/**
 75→ * Obtenir un message d'erreur de limite
 76→ */
 77→export function getLimitErrorMessage(
 78→  planTier: string,
 79→  limitType: keyof PlanLimits
 80→): string {
 81→  const limits = getPlanLimits(planTier);
 82→  const maxValue = limits[limitType];
 83→
 84→  const limitNames: Record<string, string> = {
 85→    maxSources: 'sources',
 86→    maxServices: 'services',
 87→    maxUseCases: "cas d'usage",
 88→    maxFaq: 'questions FAQ',
 89→    maxReferencePages: 'pages de référence',
 90→  };
 91→
 92→  const name = limitNames[limitType] || limitType;
 93→
 94→  if (typeof maxValue === 'number' && maxValue !== -1) {
 95→    return `Votre plan ${planTier.toUpperCase()} est limité à ${maxValue} ${name}. Passez au plan supérieur pour augmenter cette limite.`;
 96→  }
 97→
 98→  return `Cette fonctionnalité n'est pas disponible sur le plan ${planTier.toUpperCase()}. Passez au plan supérieur.`;
 99→}
