101→/**
102→ * Valider et limiter les données selon le plan
103→ * Tronque les tableaux si nécessaire
104→ */
105→export function enforceDataLimits<T extends { services?: any[]; use_cases?: any[]; faq?: any[]; reference_pages?: any[] }>(
106→  data: T,
107→  limits: PlanLimits
108→): T {
109→  const validated = { ...data };
110→
111→  // Limiter les services
112→  if (validated.services && limits.maxServices !== -1 && validated.services.length > limits.maxServices) {
113→    validated.services = validated.services.slice(0, limits.maxServices);
114→  }
115→
116→  // Limiter les use cases
117→  if (validated.use_cases && limits.maxUseCases !== -1 && validated.use_cases.length > limits.maxUseCases) {
118→    validated.use_cases = validated.use_cases.slice(0, limits.maxUseCases);
119→  }
120→
121→  // Limiter les FAQ
122→  if (validated.faq && limits.maxFaq !== -1 && validated.faq.length > limits.maxFaq) {
123→    validated.faq = validated.faq.slice(0, limits.maxFaq);
124→  }
125→
126→  // Limiter les pages de référence
127→  if (validated.reference_pages && limits.maxReferencePages !== -1 && validated.reference_pages.length > limits.maxReferencePages) {
128→    validated.reference_pages = validated.reference_pages.slice(0, limits.maxReferencePages);
129→  }
130→
131→  return validated;
132→}
