 15→export async function POST(req: NextRequest) {
 16→  try {
 17→    const body = await req.json();
 18→    const { url } = body;
 19→
 20→    if (!url) {
 21→      return NextResponse.json({ error: 'URL is required' }, { status: 400 });
 22→    }
 23→
 24→    // Run analysis
 25→    const analyzer = new AEOAnalyzer();
 26→    const result = await analyzer.analyze(url);
 27→
 28→    // For MVP: Save to database if Supabase is configured
 29→    // In production, this would check user auth and tier limits
 30→    if (supabase) {
 31→      try {
 32→        // For now, we'll create a mock user or skip database saving
 33→        // This allows testing the AEO engine without full auth setup
 34→        const { data: scan, error: scanError } = await supabase
 35→          .from('scans')
 36→          // @ts-ignore - Supabase types not fully configured yet
 37→          .insert({
 38→            url: result.url,
 39→            aeo_score: result.scores.overall,
 40→            structure_score: result.scores.structure,
 41→            citation_triggers_score: result.scores.citationTriggers,
 42→            credibility_score: result.scores.credibility,
 43→            semantic_score: result.scores.semantic,
 44→            quality_score: result.scores.quality,
 45→            chunkability_score: result.scores.aoeSpecials.chunkability,
 46→            direct_answer_density: result.scores.aoeSpecials.directAnswerDensity,
 47→            faq_score: result.scores.aoeSpecials.faqScore,
 48→            recommendations: result.recommendations,
 49→            content_data: result.raw,
 50→            short_answer_candidates: result.raw?.shortAnswerCandidates || []
 51→          })
 52→          .select()
 53→          .single();
 54→
 55→        if (scanError) {
 56→          console.warn('Database save skipped:', scanError.message);
 57→          // Continue without saving - this is OK for MVP testing
 58→        }
 59→      } catch (dbError) {
 60→        console.warn('Database error (continuing anyway):', dbError);
 61→        // Continue even if database save fails
 62→      }
 63→    }
 64→
 65→    return NextResponse.json({
 66→      success: true,
 67→      result: {
 68→        url: result.url,
 69→        scores: result.scores,
